6039   case ICmpInst::ICMP_SLT:
6040   case ICmpInst::ICMP_SLE:
6041   case ICmpInst::ICMP_ULT:
6042   case ICmpInst::ICMP_ULE:
6043     std::swap(LHS, RHS);
6044     [[fallthrough]];
6045   case ICmpInst::ICMP_SGT:
6046   case ICmpInst::ICMP_SGE:
6047   case ICmpInst::ICMP_UGT:
6048   case ICmpInst::ICMP_UGE:
6049     // a > b ? a+x : b+x  ->  max(a, b)+x
6050     // a > b ? b+x : a+x  ->  min(a, b)+x
6051     if (getTypeSizeInBits(LHS->getType()) <= getTypeSizeInBits(Ty)) {
6052       bool Signed = ICI->isSigned();
6053       const SCEV *LA = getSCEV(TrueVal);
6054       const SCEV *RA = getSCEV(FalseVal);
6055       const SCEV *LS = getSCEV(LHS);
6056       const SCEV *RS = getSCEV(RHS);
6057       if (LA->getType()->isPointerTy()) {
6058         // FIXME: Handle cases where LS/RS are pointers not equal to LA/RA.
6059         // Need to make sure we can't produce weird expressions involving
6060         // negated pointers.
6061         if (LA == LS && RA == RS)
6062           return Signed ? getSMaxExpr(LS, RS) : getUMaxExpr(LS, RS);
6063         if (LA == RS && RA == LS)
6064           return Signed ? getSMinExpr(LS, RS) : getUMinExpr(LS, RS);
6065       }
6066       auto CoerceOperand = [&](const SCEV *Op) -> const SCEV * {
6067         if (Op->getType()->isPointerTy()) {
6068           Op = getLosslessPtrToIntExpr(Op);
6069           if (isa<SCEVCouldNotCompute>(Op))
6070             return Op;
6071         }
6072         if (Signed)
6073           Op = getNoopOrSignExtend(Op, Ty);
6074         else
6075           Op = getNoopOrZeroExtend(Op, Ty);
6076         return Op;
6077       };
6078       LS = CoerceOperand(LS);
6079       RS = CoerceOperand(RS);
6080       if (isa<SCEVCouldNotCompute>(LS) || isa<SCEVCouldNotCompute>(RS))
6081         break;
6082       const SCEV *LDiff = getMinusSCEV(LA, LS);
6083       const SCEV *RDiff = getMinusSCEV(RA, RS);
6084       if (LDiff == RDiff)
6085         return getAddExpr(Signed ? getSMaxExpr(LS, RS) : getUMaxExpr(LS, RS),
