6087       LDiff = getMinusSCEV(LA, RS);
6088       RDiff = getMinusSCEV(RA, LS);
6089       if (LDiff == RDiff)
6090         return getAddExpr(Signed ? getSMinExpr(LS, RS) : getUMinExpr(LS, RS),
6091                           LDiff);
6092     }
6093     break;
6094   case ICmpInst::ICMP_NE:
6095     // x != 0 ? x+y : C+y  ->  x == 0 ? C+y : x+y
6096     std::swap(TrueVal, FalseVal);
6097     [[fallthrough]];
6098   case ICmpInst::ICMP_EQ:
